const body = $input.first().json.body || {};
const headers = $input.first().json.headers || {};

if (headers['x-gpmd-secret'] !== '$env.GPMD_WEBHOOK_SECRET') {
  return [{ json: { ok: 'false', error: 'Unauthorized' } }];
}

const phone = (body.phone || '').replace(/\D/g, '');
const cedula = (body.cedula || '').trim();

if (!phone || !cedula) {
  return [{ json: { ok: 'false', error: 'phone y cedula requeridos' } }];
}

// Generar código único GPMD-XXXXXX
const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789';
let code = 'GPMD-';
for (let i = 0; i < 6; i++) code += chars[Math.floor(Math.random() * chars.length)];

return [{ json: {
  phone,
  cedula,
  nombre_piloto: body.nombre_piloto || '',
  edad: parseInt(body.edad) || null,
  tipo_participacion: body.tipo_participacion || 'novato',
  participaciones_anteriores: parseInt(body.participaciones_anteriores) || 0,
  rh: body.rh || '',
  eps: body.eps || '',
  ciudad: body.ciudad || '',
  departamento: body.departamento || '',
  email: body.email || '',
  nombre_copiloto: body.nombre_copiloto || '',
  vehiculo_marca: body.vehiculo_marca || '',
  vehiculo_modelo: body.vehiculo_modelo || '',
  vehiculo_cilindrada: body.vehiculo_cilindrada || '',
  vehiculo_empresa: body.vehiculo_empresa || '',
  vehiculo_placa: (body.vehiculo_placa || '').toUpperCase(),
  codigo_preregistro: code,
  estado: 'slot_pendiente',
} }];

const row = $('Upsert Participante').first().json;
return [{ json: {
  ok: 'true',
  participant_id: row.id,
  codigo: row.codigo_preregistro,
  estado: row.estado,
} }];
